const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth    = headers['authorization'] || headers['Authorization'] || '';
const token   = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const auctionId = String(body.auction_id || '').trim();
const handle    = String(body.bidder_handle || '').trim();
const platform  = String(body.platform || 'manual').trim().toLowerCase();
let maxCents = body.max_cents != null ? parseInt(body.max_cents, 10) : null;
if ((maxCents == null || isNaN(maxCents)) && body.max_amount != null) {
  const d = parseFloat(String(body.max_amount).replace(/[^0-9.]/g, ''));
  if (!isNaN(d) && d > 0) maxCents = Math.round(d * 100);
}
if (!auctionId) return { json: { ok: false, status: 400, error: 'auction_id required' } };
if (!handle)    return { json: { ok: false, status: 400, error: 'bidder_handle required' } };
if (maxCents == null || isNaN(maxCents) || maxCents <= 0) return { json: { ok: false, status: 400, error: 'a positive max (max_amount or max_cents) is required' } };
return { json: { token: token, auction_id: auctionId, handle: handle, platform: platform, max_cents: maxCents } };

const rows = $input.item.json;
const row  = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
const x = $('Extract').item.json;
return { json: { ok: true, auction_id: x.auction_id, handle: x.handle, platform: x.platform, max_cents: x.max_cents } };

let r = $input.item.json;
if (Array.isArray(r)) r = r[0] || {};
if (r == null || typeof r !== 'object') r = { ok: false, status: 500, error: 'Unexpected DB response' };
if (r.ok) {
  const res = r.resolution || {};
  return { json: { ok: true, status: 200, max_cents: r.max_cents, max_display: r.max_cents != null ? ('$' + (r.max_cents/100).toFixed(2)) : null, auto_bid_placed: !!res.auto_bid, new_high_cents: res.amount_cents != null ? res.amount_cents : null, new_high_display: res.amount_cents != null ? ('$' + (res.amount_cents/100).toFixed(2)) : null } };
}
return { json: { ok: false, status: r.status || 500, error: r.error || 'Auto-bid failed' } };
